import{_ as d,o as e,c as o,a2 as a}from"./chunks/framework.CW5cCyjm.js";const _=JSON.parse('{"title":"Admin UI 通用规范","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/frontend/07-admin-ui-common.md","filePath":"mango-pmo/rules/frontend/07-admin-ui-common.md"}'),r={name:"mango-pmo/rules/frontend/07-admin-ui-common.md"};function i(l,t,c,n,m,s){return e(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="admin-ui-通用规范" tabindex="-1">Admin UI 通用规范 <a class="header-anchor" href="#admin-ui-通用规范" aria-label="Permalink to &quot;Admin UI 通用规范&quot;">​</a></h1><h2 id="_1-目标" tabindex="-1">1. 目标 <a class="header-anchor" href="#_1-目标" aria-label="Permalink to &quot;1. 目标&quot;">​</a></h2><p>Mango Admin UI 以系统级一致性为最高优先级。</p><p>相同语义、相同层级、相同功能的界面元素，必须在布局、尺寸、间距、颜色、文案、图标、命名和交互上保持一致。</p><h2 id="_2-必须遵守" tabindex="-1">2. 必须遵守 <a class="header-anchor" href="#_2-必须遵守" aria-label="Permalink to &quot;2. 必须遵守&quot;">​</a></h2><ol><li>同类页面必须使用统一结构，禁止每个页面自定义一套布局。</li><li>页面内容区不展示面包屑、页签标题、路由层级；这些属于框架能力。</li><li>非必要不覆盖 Element Plus 基础控件样式。</li><li>输入框、下拉、按钮、表格、弹框等基础控件尺寸由统一样式表控制。</li><li>页面私有样式只处理业务布局和特殊展示，不定义新的控件规范。</li><li>系统主色、语义色、圆角、阴影、间距必须来自统一变量或统一样式。</li><li>相同语义的操作必须使用相同图标，图标来自 Element Plus Icons 或项目统一图标库。</li><li>删除、移除、清空等危险操作统一使用 <code>danger</code>。</li><li>页面必须覆盖 loading、empty、error 和无权限状态。</li><li>特殊页面可以例外，但必须说明原因，基础控件仍尽量遵守统一样式。</li></ol><h2 id="_3-命名约定" tabindex="-1">3. 命名约定 <a class="header-anchor" href="#_3-命名约定" aria-label="Permalink to &quot;3. 命名约定&quot;">​</a></h2><p>页面变量、方法、权限标识和按钮语义优先使用统一动作词：</p><table tabindex="0"><thead><tr><th>中文</th><th>英文</th></tr></thead><tbody><tr><td>新增</td><td><code>add</code></td></tr><tr><td>编辑</td><td><code>edit</code></td></tr><tr><td>删除</td><td><code>delete</code></td></tr><tr><td>查看</td><td><code>view</code></td></tr><tr><td>查询</td><td><code>search</code></td></tr><tr><td>重置</td><td><code>reset</code></td></tr><tr><td>提交</td><td><code>submit</code></td></tr><tr><td>保存</td><td><code>save</code></td></tr><tr><td>取消</td><td><code>cancel</code></td></tr><tr><td>返回</td><td><code>back</code></td></tr><tr><td>启用</td><td><code>enable</code></td></tr><tr><td>停用</td><td><code>disable</code></td></tr><tr><td>导入</td><td><code>import</code></td></tr><tr><td>导出</td><td><code>export</code></td></tr><tr><td>刷新</td><td><code>refresh</code></td></tr></tbody></table><p>禁止同一语义混用多套命名，例如 <code>add/create/new</code>、<code>view/detail/info</code>、<code>delete/remove/del</code>。</p><h2 id="_4-禁止事项" tabindex="-1">4. 禁止事项 <a class="header-anchor" href="#_4-禁止事项" aria-label="Permalink to &quot;4. 禁止事项&quot;">​</a></h2><ol><li>禁止页面内硬编码新的颜色、控件高度、圆角、阴影、间距规则。</li><li>禁止使用 emoji、字符箭头、临时 SVG 替代统一图标。</li><li>禁止为了接口字段顺序或开发便利性牺牲业务阅读顺序。</li><li>禁止把页面能打开当作 UI 完成，必须检查布局、状态、交互和异常场景。</li></ol>',12)])])}const u=d(r,[["render",i]]);export{_ as __pageData,u as default};
